// src/pages/Notes.jsx
import React, { useState, useEffect } from "react";
import { useAuth } from "../context/AuthContext";
import { useNavigate } from "react-router-dom";

export default function Notes() {
  const { currentUser } = useAuth();
  const navigate = useNavigate();

  const [notes, setNotes] = useState(() => {
    const saved = localStorage.getItem("notes");
    return saved ? JSON.parse(saved) : [];
  });

  const [file, setFile] = useState(null);
  const [title, setTitle] = useState("");
  const [search, setSearch] = useState("");

  useEffect(() => {
    if (!currentUser) navigate("/login");
  }, [currentUser, navigate]);

  const handleUpload = (e) => {
    e.preventDefault();
    if (!title || !file) return alert("Please enter title and upload a file.");

    const newNote = {
      id: Date.now(),
      title,
      fileName: file.name,
      fileURL: URL.createObjectURL(file),
      uploader: currentUser.name,
      uploadedAt: new Date().toLocaleString(),
    };

    const updatedNotes = [newNote, ...notes];
    setNotes(updatedNotes);
    localStorage.setItem("notes", JSON.stringify(updatedNotes));

    setTitle("");
    setFile(null);
  };

  const handleDelete = (id) => {
    if (!window.confirm("Are you sure you want to delete this note?")) return;
    const updated = notes.filter((n) => n.id !== id);
    setNotes(updated);
    localStorage.setItem("notes", JSON.stringify(updated));
  };

  const filteredNotes = notes.filter((note) =>
    note.title.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div className="p-6 max-w-4xl mx-auto">
      <h1 className="text-3xl font-bold mb-4">📚 Notes</h1>

      <form onSubmit={handleUpload} className="mb-6 p-4 border rounded-lg">
        <h2 className="text-xl font-semibold mb-2">Upload Note</h2>
        <input
          type="text"
          placeholder="Title of note"
          value={title}
          onChange={(e) => setTitle(e.target.value)}
          className="block w-full border px-3 py-2 mb-3 rounded"
        />
        <input
          type="file"
          accept=".pdf,.doc,.docx"
          onChange={(e) => setFile(e.target.files[0])}
          className="block mb-3"
        />
        <button
          type="submit"
          className="bg-green-600 text-white px-4 py-2 rounded hover:bg-green-700"
        >
          Upload
        </button>
      </form>

      <input
        type="text"
        placeholder="Search notes..."
        value={search}
        onChange={(e) => setSearch(e.target.value)}
        className="w-full border px-3 py-2 mb-4 rounded"
      />

      {filteredNotes.length === 0 ? (
        <p className="text-gray-600">No notes found.</p>
      ) : (
        <ul className="space-y-4">
          {filteredNotes.map((note) => (
            <li
              key={note.id}
              className="p-4 border rounded-lg flex justify-between items-center"
            >
              <div>
                <h3 className="font-semibold text-lg">{note.title}</h3>
                <p className="text-sm text-gray-600">
                  Uploaded by: <b>{note.uploader}</b> | {note.uploadedAt}
                </p>
                <a
                  href={note.fileURL}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="text-blue-600 underline text-sm"
                >
                  View / Download
                </a>
              </div>
              {currentUser.role === "admin" && (
                <button
                  onClick={() => handleDelete(note.id)}
                  className="text-red-600 hover:underline text-sm"
                >
                  Delete
                </button>
              )}
            </li>
          ))}
        </ul>
      )}
    </div>
  );
}
